namespace Maliev.CurrencyService.Infrastructure.Data.SeedData;

/// <summary>
/// Provides static currency seed data for database initialization.
/// </summary>
public static partial class CurrencySeedData
{
    private static Guid GenerateDeterministicGuid(string code)
    {
        var hash = SHA256.HashData(Encoding.UTF8.GetBytes(code));
        var bytes = new byte[16];
        Array.Copy(hash, bytes, 16);
        bytes[6] = (byte)((bytes[6] & 0x0f) | 0x50);
        bytes[8] = (byte)((bytes[8] & 0x3f) | 0x80);
        return new Guid(bytes);
    }

